import{_ as e,o as s,c as r,ae as n}from"./chunks/framework.CL3pmU-5.js";const a="/ComputerNetwork/assets/%E8%AE%A1%E7%AE%97%E6%9C%BA%E7%BD%91%E7%BB%9C.BMCcL_Dp.svg",o="/ComputerNetwork/assets/%E7%BD%91%E7%BB%9C%E8%BF%9E%E6%8E%A5.DJg444np.svg",u=JSON.parse('{"title":"1.1 什么是Internet","description":"","frontmatter":{},"headers":[],"relativePath":"第一章/1.1 什么是Internet.md","filePath":"第一章/1.1 什么是Internet.md"}'),i={name:"第一章/1.1 什么是Internet.md"};function l(_,t,p,c,m,d){return s(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="_1-1-什么是internet" tabindex="-1">1.1 什么是Internet <a class="header-anchor" href="#_1-1-什么是internet" aria-label="Permalink to &quot;1.1 什么是Internet&quot;">​</a></h1><p>下面这张图初步介绍了什么是计算机网络？</p><p><img src="'+a+'" alt="网络"></p><ol><li>网络：是由节点和边构成的系统</li><li>计算机网络：是由主机节点和交换节点相互连接构成的系统</li><li>互联网：是由一个个孤立的计算机网络相互连接构成的系统</li></ol><details class="details custom-block"><summary>Details</summary><p>交换节点有：交换机（链路层），路由器（网络层），网络负载均衡设备</p></details><p>下面这张图一个大圈圈就是一个计算机网络，把这些单独的计算机网络连接起来，就形成了<strong>互联网</strong></p><p><img src="'+o+'" alt="两个进程的连接"></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>从这张图中得到，<strong>互联网</strong>是分布式的应用进程，以及为分布式应用进程提供通信服务的基础设施。</p></div><p><strong>协议</strong>：对等层实体在通讯过程中应该遵循的规则集合。</p>',9)])])}const g=e(i,[["render",l]]);export{u as __pageData,g as default};
